export const meta = { name: 'camiel-roadmap', description: 'Find roadmap status for Project-Camiel', phases: [{ title: 'Gather' }, { title: 'Synthesize' }] };

phase('Gather');

const result = await agent(`In /Volumes/T9/Code/projects/Project-Camiel, find any roadmap, changelog, todo, or project-status documents. Run ALL of the following commands and read ALL of these files:

1. ls -la (root)
2. find . -maxdepth 2 -iname "roadmap*" -o -iname "changelog*" -o -iname "todo*" -o -iname "plan*" -o -iname "next*" 2>/dev/null
3. cat package.json
4. git branch -a && git tag -l && git log --oneline -15 && git remote -v
5. ls .claude/ 2>/dev/null && cat .claude/CLAUDE.md 2>/dev/null
6. ls .github/ 2>/dev/null; ls .gitlab/ 2>/dev/null
7. glab project list --mine 2>/dev/null; glab issue list 2>/dev/null; glab milestone list 2>/dev/null
8. find src/app -maxdepth 2 -type d 2>/dev/null
9. Check for any docs/ directory

Also check: /Volumes/T9/Code/projects/athena/.claude/CLAUDE.md and any ROADMAP* files there.

Return ALL output verbatim.`, { label: 'camiel-roadmap-gather', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' });

phase('Synthesize');

const summary = await agent(`Synthesize a roadmap status report from this raw output. Format:
## Project-Camiel Roadmap Status
### Version
### Planned/In-Progress
### Gaps

--- RAW ---
${result || 'No output'}
`, { label: 'synthesize', tier: 'small', cwd: '/Volumes/T9/Code/projects/Project-Camiel' });

return { ok: true, raw: result, summary };
